//! fact raw_to_fact：把 adapter 输出收敛为 `FactRow`。
//!
//! 设计动机：
//! - 这里做“事实形状收敛”，不做 worldview 语义解释。
//! - key canonicalization 的 owner 在 adapter；normalize 不做字段重命名。
//! - 这一层只做类型收敛，避免把数据源语义和世界观语义耦合在公共路径上。

use std::collections::BTreeMap;

use materia::identity::{CodeVersion, SourceFingerprint};

use crate::adapter::registry::{RawRow, RawValue};
use crate::model::{FactBatch, FactRow, PrimitiveValue, TimeViewId};

use super::batch_builder;
use super::row_invariants;
pub use super::row_invariants::NormalizeError;

pub fn normalize_rows(
    rows: Vec<RawRow>,
) -> Result<Vec<FactRow>, NormalizeError> {
    let mut fact_rows = Vec::with_capacity(rows.len());

    for (index, row) in rows.into_iter().enumerate() {
        row_invariants::validate_row(index, &row)?;

        let mut fields = BTreeMap::new();
        for (key, raw_val) in row.fields {
            let pv = match raw_val {
                RawValue::F64(v) => PrimitiveValue::Float(v),
                RawValue::I64(v) => PrimitiveValue::Int(v),
                RawValue::Text(v) => PrimitiveValue::Text(v),
                RawValue::Bool(v) => PrimitiveValue::Bool(v),
            };

            fields.insert(key, pv);
        }

        fact_rows.push(FactRow {
            timestamp: row.timestamp_ms,
            fields,
        });
    }

    Ok(fact_rows)
}

pub fn assemble_normalized_batch(
    fact_rows: Vec<FactRow>,
    symbol: &str,
    time_view_id: TimeViewId,
    source_fingerprint: SourceFingerprint,
    code_version: CodeVersion,
) -> Result<FactBatch, NormalizeError> {
    batch_builder::assemble_normalized_batch(
        fact_rows,
        symbol,
        time_view_id,
        source_fingerprint,
        code_version,
    )
}

