mod tests {
    use std::collections::BTreeMap;

    use crate::adapter::registry::{InterfaceFamily, RawRow, RawValue};
    use crate::model::PrimitiveValue;

    use super::normalize_rows;

    #[test]
    fn normalize_maps_values_and_keeps_adapter_keys() {
        let mut fields = BTreeMap::new();
        fields.insert("bar:open".to_string(), RawValue::F64(1.2));
        fields.insert("bar:high".to_string(), RawValue::F64(1.3));
        fields.insert("bar:low".to_string(), RawValue::F64(1.1));
        fields.insert("bar:close".to_string(), RawValue::F64(1.25));
        fields.insert("bar:volume".to_string(), RawValue::I64(10));
        fields.insert("source".to_string(), RawValue::Text("okx".to_string()));
        fields.insert("real".to_string(), RawValue::Bool(true));

        let rows = vec![RawRow {
            adapter: "okx".to_string(),
            family: InterfaceFamily::Kline,
            symbol: "BTC-USDT".to_string(),
            timestamp_ms: 1000,
            fields,
        }];

        let fact_rows = normalize_rows(rows).expect("normalize ok");
        let fact = fact_rows.first().expect("one fact");

        assert_eq!(fact.timestamp, 1000);
        assert_eq!(fact.fields.get("bar:open"), Some(&PrimitiveValue::Float(1.2)));
        assert_eq!(fact.fields.get("bar:high"), Some(&PrimitiveValue::Float(1.3)));
        assert_eq!(fact.fields.get("bar:low"), Some(&PrimitiveValue::Float(1.1)));
        assert_eq!(fact.fields.get("bar:close"), Some(&PrimitiveValue::Float(1.25)));
        assert_eq!(fact.fields.get("bar:volume"), Some(&PrimitiveValue::Int(10)));
        assert_eq!(
            fact.fields.get("source"),
            Some(&PrimitiveValue::Text("okx".to_string()))
        );
        assert_eq!(fact.fields.get("real"), Some(&PrimitiveValue::Bool(true)));
    }
}


