//! Service 层——market-ingest 的唯一对外入口。
//!
//! 编排 adapter -> fact -> signal 三条执行链，并以 `ReplayContractRef`
//! 作为 replay 主入参，避免隐式状态补全。
//!
//! 设计原则：
//! - service 只做编排，不承载 adapter SDK 细节。
//! - service 不解释 worldview 语义，只消费执行规格。
//! - replay 只消费显式合同与显式事实，不依赖进程内隐式状态。

use std::fmt;

use crate::adapter::{self, InterfaceFamily, RawRow, RegistryError};
use crate::model::{
    BatchId, FactBatch, IngestReceipt, MaterializeReceipt, ReplayContract, ReplayContractRef,
    ReplayReceipt, SignalBatch, TimePeriod, TimeViewId, Timezone, WorldviewExecutionSpec,
};
use crate::fact::{self, journal_port::JournalPort, NormalizeError};
use crate::signal::{self, ProjectionError};
use materia::identity::{CodeVersion, SourceFingerprint};

#[derive(Debug)]
pub enum ServiceError {
    Adapter(RegistryError),
    Normalize(NormalizeError),
    Projection(ProjectionError),
    BatchNotFound(BatchId),
    ContractNotFound(ReplayContractRef),
    Journal(String),
    ReplayMismatch {
        field: String,
        expected: String,
        actual: String,
    },
}

impl fmt::Display for ServiceError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::Adapter(e) => write!(f, "adapter: {e}"),
            Self::Normalize(e) => write!(f, "normalize: {e}"),
            Self::Projection(e) => write!(f, "projection: {e}"),
            Self::BatchNotFound(id) => write!(f, "batch not found: {:?}", id),
            Self::ContractNotFound(id) => write!(f, "replay contract not found: {:?}", id),
            Self::Journal(e) => write!(f, "journal: {e}"),
            Self::ReplayMismatch {
                field,
                expected,
                actual,
            } => write!(
                f,
                "replay mismatch on '{field}': expected {expected}, got {actual}"
            ),
        }
    }
}

impl std::error::Error for ServiceError {}

impl From<RegistryError> for ServiceError {
    fn from(value: RegistryError) -> Self {
        Self::Adapter(value)
    }
}

impl From<NormalizeError> for ServiceError {
    fn from(value: NormalizeError) -> Self {
        Self::Normalize(value)
    }
}

impl From<ProjectionError> for ServiceError {
    fn from(value: ProjectionError) -> Self {
        Self::Projection(value)
    }
}

pub struct IngestService<J: JournalPort> {
    // 设计动机：replay 不依赖进程隐式状态，所有可复算事实都通过 journal 显式持久。
    journal: J,
}

impl IngestService<fact::journal_port::MemoryJournal> {
    pub fn new() -> Self {
        Self {
            journal: fact::journal_port::MemoryJournal::default(),
        }
    }
}

impl Default for IngestService<fact::journal_port::MemoryJournal> {
    fn default() -> Self {
        Self::new()
    }
}

impl<J: JournalPort> IngestService<J> {
    pub fn with_journal(journal: J) -> Self {
        Self { journal }
    }

    pub fn ingest_batch(
        &mut self,
        adapter: &str,
        family: InterfaceFamily,
        symbol: &str,
        period: TimePeriod,
        timezone: Timezone,
        time_view_id: TimeViewId,
        limit: usize,
        source_fingerprint: SourceFingerprint,
        code_version: CodeVersion,
    ) -> Result<IngestReceipt, ServiceError> {
        // source_fingerprint 是跨执行可复算锚点。
        validate_source_fingerprint(&source_fingerprint)?;
        let period_str = period_to_provider_str(&period);
        let timezone_str = timezone.as_provider_str();
        let rows = adapter::fetch_raw_rows(adapter, family, symbol, period_str, timezone_str, limit)?;
        self.ingest_from_rows(
            rows,
            symbol,
            time_view_id,
            source_fingerprint,
            code_version,
        )
    }

    pub fn ingest_from_rows(
        &mut self,
        rows: Vec<RawRow>,
        symbol: &str,
        time_view_id: TimeViewId,
        source_fingerprint: SourceFingerprint,
        code_version: CodeVersion,
    ) -> Result<IngestReceipt, ServiceError> {
        validate_source_fingerprint(&source_fingerprint)?;
        let fact_rows = fact::normalize_rows(rows)?;
        let batch = fact::assemble_normalized_batch(
            fact_rows,
            symbol,
            time_view_id,
            source_fingerprint,
            code_version,
        )?;
        self.journal
            .append_fact_batch(batch.clone())
            .map_err(ServiceError::Journal)?;
        let ingest_receipt = fact::batch_builder::build_ingest_receipt(&batch);
        self.journal
            .append_ingest(ingest_receipt.clone())
            .map_err(ServiceError::Journal)?;
        Ok(ingest_receipt)
    }

    pub fn materialize(
        &mut self,
        batch_id: &BatchId,
        execution_spec: &WorldviewExecutionSpec,
        code_version: CodeVersion,
    ) -> Result<(SignalBatch, MaterializeReceipt), ServiceError> {
        // 先拿 worldview 无关事实闭包，再做 worldview 绑定投影。
        // 注意：这里使用的是执行规约化规格（worldview_pin + signal_keys），
        // 不是完整 worldview 治理对象。
        // service 只负责编排统一解释内核（gate -> mapper），
        // 把“事实是否满足这份执行需求”跑通；
        // 不在本层解释 owner/dimensions 等治理语义，也不写 worldview 分支。
        let batch = self.get_batch(batch_id)?;
        let (signal_samples, _decision, _sidecar) = signal::project_facts(
            &batch.fact_rows,
            execution_spec,
            &batch.time_view_id,
        )?;

        // contract_ref 由稳定锚点确定性复现。
        let contract_ref = ReplayContractRef(format!(
            "replay:{}:{}:{}",
            batch.batch_id.0,
            execution_spec.worldview_pin.id.0,
            execution_spec.worldview_pin.version.0
        ));
        let execution_spec_fingerprint = execution_spec_fingerprint(execution_spec);
        let replay_contract = ReplayContract {
            contract_ref: contract_ref.clone(),
            replay_anchor: crate::model::ReplayAnchor {
                batch_id: batch.batch_id.clone(),
                source_fingerprint: batch.source_fingerprint.clone(),
                time_view_id: batch.time_view_id.clone(),
                code_version: code_version.clone(),
                fact_count: batch.fact_count,
                time_range: batch.time_range,
                lineage_ref: format!(
                    "lineage:{}:{}",
                    batch.batch_id.0, batch.source_fingerprint.0
                ),
            },
            worldview_pin: execution_spec.worldview_pin.clone(),
            execution_spec_fingerprint,
        };
        self.journal
            .append_replay_contract(replay_contract.clone())
            .map_err(ServiceError::Journal)?;

        // SignalBatch 只承载物化产物；事实体通过 batch_id 回查 FactBatch。
        let materialized = SignalBatch {
            batch_id: batch.batch_id.clone(),
            worldview_pin: execution_spec.worldview_pin.clone(),
            time_view_id: batch.time_view_id.clone(),
            source_fingerprint: batch.source_fingerprint.clone(),
            code_version,
            symbol: batch.symbol.clone(),
            signal_samples: signal_samples,
            replay_anchor: replay_contract.replay_anchor.clone(),
        };
        let receipt = MaterializeReceipt {
            batch_id: batch.batch_id.clone(),
            replay_contract_ref: contract_ref,
        };

        Ok((materialized, receipt))
    }

    pub fn replay(
        &self,
        contract_ref: &ReplayContractRef,
        execution_spec: &WorldviewExecutionSpec,
    ) -> Result<(SignalBatch, ReplayReceipt), ServiceError> {
        // replay 与 materialize 复用同一份执行规约化规格，
        // 保证复算的是同一执行面，而不是二次解释 worldview 语义。
        // 这保证了：同事实闭包 + 同执行规格 -> 同信号产物排序与内容。
        let replay_contract = self
            .journal
            .query_replay_contract(contract_ref)
            .ok_or_else(|| ServiceError::ContractNotFound(contract_ref.clone()))?;

        if replay_contract.replay_anchor.lineage_ref.trim().is_empty() {
            return Err(ServiceError::ReplayMismatch {
                field: "lineage_ref".to_string(),
                expected: "non-empty".to_string(),
                actual: "empty".to_string(),
            });
        }

        check_match(
            "worldview_pin",
            &format!("{:?}", replay_contract.worldview_pin),
            &format!("{:?}", execution_spec.worldview_pin),
        )?;
        check_match(
            "execution_spec_fingerprint",
            &replay_contract.execution_spec_fingerprint,
            &execution_spec_fingerprint(execution_spec),
        )?;

        let batch = self.get_batch(&replay_contract.replay_anchor.batch_id)?;
        check_match(
            "source_fingerprint",
            &format!("{:?}", replay_contract.replay_anchor.source_fingerprint),
            &format!("{:?}", batch.source_fingerprint),
        )?;
        check_match(
            "time_view_id",
            &replay_contract.replay_anchor.time_view_id,
            &batch.time_view_id,
        )?;

        let (signal_samples, _decision, _sidecar) = signal::project_facts(
            &batch.fact_rows,
            execution_spec,
            &batch.time_view_id,
        )?;

        let materialized = SignalBatch {
            batch_id: batch.batch_id.clone(),
            worldview_pin: execution_spec.worldview_pin.clone(),
            time_view_id: batch.time_view_id.clone(),
            source_fingerprint: batch.source_fingerprint.clone(),
            code_version: replay_contract.replay_anchor.code_version.clone(),
            symbol: batch.symbol.clone(),
            signal_samples: signal_samples,
            replay_anchor: replay_contract.replay_anchor.clone(),
        };

        let receipt = ReplayReceipt {
            batch_id: batch.batch_id.clone(),
            replay_contract_ref: contract_ref.clone(),
        };

        Ok((materialized, receipt))
    }

    pub fn get_batch(&self, batch_id: &BatchId) -> Result<FactBatch, ServiceError> {
        self.journal
            .query_fact_batch(batch_id)
            .ok_or_else(|| ServiceError::BatchNotFound(batch_id.clone()))
    }
}

fn check_match(field: &str, expected: &str, actual: &str) -> Result<(), ServiceError> {
    if expected != actual {
        return Err(ServiceError::ReplayMismatch {
            field: field.to_owned(),
            expected: expected.to_owned(),
            actual: actual.to_owned(),
        });
    }
    Ok(())
}

fn execution_spec_fingerprint(spec: &WorldviewExecutionSpec) -> String {
    let mut entries = Vec::with_capacity(spec.signal_keys.len());
    for key_spec in &spec.signal_keys {
        let value_domain = format!("{:?}", key_spec.value_domain);
        entries.push(format!(
            "{}:{}|{}:{}|{}:{}",
            key_spec.key.len(),
            key_spec.key,
            value_domain.len(),
            value_domain,
            key_spec.description.len(),
            key_spec.description
        ));
    }
    entries.sort_unstable();
    let mut canonical = format!("signal_keys_count={};", entries.len());
    canonical.push_str(&entries.join(";"));
    format!("esf:v1:{:016x}", fnv1a64(canonical.as_bytes()))
}

fn fnv1a64(input: &[u8]) -> u64 {
    let mut hash: u64 = 0xcbf29ce484222325;
    for byte in input {
        hash ^= u64::from(*byte);
        hash = hash.wrapping_mul(0x100000001b3);
    }
    hash
}

fn period_to_provider_str(period: &TimePeriod) -> &'static str {
    match period {
        TimePeriod::Min1 => "1m",
        TimePeriod::Min5 => "5m",
        TimePeriod::Min15 => "15m",
        TimePeriod::Min30 => "30m",
        TimePeriod::Hour1 => "1h",
        TimePeriod::Hour4 => "4h",
        TimePeriod::Daily => "1d",
        TimePeriod::Weekly => "1w",
        TimePeriod::Monthly => "1M",
    }
}

fn validate_source_fingerprint(fp: &SourceFingerprint) -> Result<(), ServiceError> {
    let s = fp.0.trim();
    if s.is_empty() {
        return Err(ServiceError::Journal(
            "source_fingerprint must not be empty".to_string(),
        ));
    }
    if s.contains('/')
        || s.contains('\\')
        || s.contains('#')
        || s.contains('\n')
        || s.contains('\t')
    {
        // 路径分隔符/注释符会破坏跨环境可复算性。
        return Err(ServiceError::Journal(
            "source_fingerprint contains unstable path/comment characters".to_string(),
        ));
    }
    Ok(())
}

