    #[test]
    fn replay_works_across_service_instances_via_journal_fact_batch() {
        let shared_journal = SharedMemoryJournal::default();
        let mut writer = IngestService::with_journal(shared_journal.clone());
        let ingest_receipt = writer
            .ingest_from_rows(
                local_rows(),
                "BTCUSDT",
                "tv/1m".to_string(),
                SourceFingerprint("okx-local-btcusdt".to_string()),
                CodeVersion("v0.1-local".to_string()),
            )
            .expect("local ingest should succeed");
        let spec = live_execution_spec();
        let (_materialized, materialize_receipt) = writer
            .materialize(
                &ingest_receipt.batch_id,
                &spec,
                CodeVersion("v0.1-local".to_string()),
            )
            .expect("materialize should succeed");

        let reader = IngestService::with_journal(shared_journal);
        let (replayed, replay_receipt) = reader
            .replay(&materialize_receipt.replay_contract_ref, &spec)
            .expect("replay should succeed across service instances");

        assert_eq!(replayed.batch_id, ingest_receipt.batch_id);
        assert_eq!(
            replay_receipt.replay_contract_ref,
            materialize_receipt.replay_contract_ref
        );
