                local_rows(),
                "BTCUSDT",
                "tv/1m".to_string(),
                SourceFingerprint("okx-local-btcusdt".to_string()),
                CodeVersion("v0.1-local".to_string()),
            )
            .expect("local ingest should succeed");
        let spec = live_execution_spec();

        service
            .materialize(
                &ingest_receipt.batch_id,
                &spec,
                CodeVersion("v0.1-local".to_string()),
            )
            .expect("first materialize should succeed");

        let err = service
            .materialize(
                &ingest_receipt.batch_id,
                &spec,
                CodeVersion("v0.2-local".to_string()),
            )
            .expect_err("second materialize with changed replay anchor must fail");

        match err {
            ServiceError::Journal(msg) => {
                assert!(msg.contains("replay contract ref conflict"));
            }
            other => panic!("expected Journal conflict error, got {other:?}"),
        }
    }

    #[test]
    fn ingest_batch_rejects_non_utc_timezone() {
        let mut service = IngestService::new();
        let err = service
            .ingest_batch(
                "okx",
                InterfaceFamily::Kline,
                "BTCUSDT",
                TimePeriod::Daily,
                Timezone::AsiaShanghai,
                "tv/1d".to_string(),
                5,
                SourceFingerprint("okx-live-btcusdt".to_string()),
                CodeVersion("v0.1-live".to_string()),
            )
            .expect_err("non-UTC timezone should be rejected before adapter pull");

        assert!(
            err.to_string().contains("unsupported timezone"),
            "unexpected error: {err:?}"
        );
    }

    #[test]
    #[ignore = "requires external network and OKX public API availability"]
    fn live_okx_ingest_materialize_replay() {
        let mut service = IngestService::new();
        let ingest_receipt = service
            .ingest_batch(
                "okx",
                InterfaceFamily::Kline,
                "BTCUSDT",
                TimePeriod::Daily,
                Timezone::Utc,
                "tv/1d".to_string(),
                5,
                SourceFingerprint("okx-live-btcusdt".to_string()),
                CodeVersion("v0.1-live".to_string()),
            )
            .expect("okx ingest should return bars");

        let spec = live_execution_spec();
        let (materialized, materialize_receipt) = service
            .materialize(
                &ingest_receipt.batch_id,
                &spec,
                CodeVersion("v0.1-live".to_string()),
            )
            .expect("materialize should succeed");

        assert!(!service.get_batch(&ingest_receipt.batch_id).unwrap().fact_rows.is_empty());
        assert_eq!(
            materialized.signal_samples.len(),
            service.get_batch(&ingest_receipt.batch_id).unwrap().fact_count * 5
        );

        let (replayed, replay_receipt) = service
            .replay(&materialize_receipt.replay_contract_ref, &spec)
            .expect("replay should succeed");

        assert_eq!(replayed.signal_samples.len(), materialized.signal_samples.len());
        assert_eq!(
            replay_receipt.replay_contract_ref,
            materialize_receipt.replay_contract_ref
        );
    }
